class Solution:
    def shipWithinDays(self, weights: List[int], days: int) -> int:
        def can_ship(capacity):
            count = 1
            curr_weight = 0
            for weight in weights:
                curr_weight += weight
                if curr_weight > capacity:
                    count += 1
                    curr_weight = weight
                if count > days:
                    return False
            return True

        left, right = max(weights), sum(weights)
        while left < right:
            mid = (left + right) // 2
            if can_ship(mid):
                right = mid
            else:
                left = mid + 1
        return left
